def calculate_loan_payback_period(principal, annual_interest_rate, monthly_payment):
    if monthly_payment <= 0:
        raise ValueError("Monthly payment must be greater than zero.")
    if principal <= 0:
        raise ValueError("Principal must be greater than zero.")
    if annual_interest_rate < 0:
        raise ValueError("Annual interest rate cannot be negative.")

    monthly_interest_rate = annual_interest_rate / 12 / 100
    months = 0
    while principal > 0:
        interest_for_the_month = principal * monthly_interest_rate
        principal += interest_for_the_month
        principal -= monthly_payment
        months += 1
        if months > 1000:  # Prevent infinite loop in case of unrealistic inputs
            raise ValueError("Loan cannot be paid back with the given monthly payment.")

    return months

def calculate_monthly_payment(principal, annual_interest_rate, payback_period):
    if payback_period <= 0:
        raise ValueError("Payback period must be greater than zero.")
    if principal <= 0:
        raise ValueError("Principal must be greater than zero.")
    if annual_interest_rate < 0:
        raise ValueError("Annual interest rate cannot be negative.")

    monthly_interest_rate = annual_interest_rate / 12 / 100
    if monthly_interest_rate == 0:
        return principal / payback_period

    monthly_payment = (principal * monthly_interest_rate) / (1 - (1 + monthly_interest_rate) ** -payback_period)
    return monthly_payment

def solve(principal, annual_interest_rate, monthly_payment=None, payback_period=None):
    if monthly_payment is not None:
        return calculate_loan_payback_period(principal, annual_interest_rate, monthly_payment)
    elif payback_period is not None:
        return calculate_monthly_payment(principal, annual_interest_rate, payback_period)
    else:
        raise ValueError("Either monthly_payment or payback_period must be provided.")
